// Validate incoming payload from WF10 and build welcome message
const data = $input.first().json;

// WF10 sends: patient_code, name, phone, clinic_name, doctor_name, follow_up_required, follow_up_date, visit_date
const name = String(data.name || data.patient_name || '').trim();
const phone = String(data.phone || '').trim();
const patientCode = String(data.patient_code || '').trim();
const clinicName = String(data.clinic_name || $env.DEFAULT_CLINIC_NAME || 'our clinic').trim();
const doctorName = String(data.doctor_name || $env.DEFAULT_DOCTOR_NAME || 'your doctor').trim();
const followUpRequired = String(data.follow_up_required || 'No').trim();
const followUpDate = data.follow_up_date || null;

if (!phone || !/^\+[1-9]\d{6,14}$/.test(phone)) {
  return [{ json: { _skip: true, reason: `Invalid phone received from WF10: ${phone}`, patientCode } }];
}

if (!name) {
  return [{ json: { _skip: true, reason: 'Empty patient name received from WF10', patientCode } }];
}

// Build welcome message
let welcomeMsg = `Hi ${name}! 👋 Welcome to ${clinicName}. We've noted your visit with ${doctorName} and your records are now in our system.\n\n`;

if (followUpRequired === 'Yes' && followUpDate) {
  const fuDisplay = new Date(followUpDate).toLocaleDateString('en-IN', { day: 'numeric', month: 'long', year: 'numeric' });
  welcomeMsg += `Your follow-up appointment is scheduled for *${fuDisplay}*. We'll send you a reminder closer to the date.\n\n`;
} else {
  welcomeMsg += `Your doctor will guide you on next steps. `;
}

welcomeMsg += `If you have any questions, feel free to reply to this message. Take care! 💙`;

return [{
  json: {
    _skip: false,
    _patient_name: name,
    _phone: phone,
    _patient_code: patientCode,
    _to_phone: 'whatsapp:' + phone,
    _message_body: welcomeMsg,
    _message_type: 'welcome'
  }
}];
